examples.code:
// Basic labelled textarea
<Textarea
  label="Description"
  placeholder="Enter a description…"
  value={description}
  onChangeText={setDescription}
/>

// Capped height with character counter
<Textarea
  label="Bio"
  maxLength={300}
  maxHeight={200}
  value={bio}
  onChangeText={setBio}
/>

// Error state
<Textarea
  label="Notes"
  value={notes}
  onChangeText={setNotes}
  error="Notes cannot be empty"
/>

// Disabled textarea pre-filled with read-only content
<Textarea
  label="System Log"
  value={logOutput}
  onChangeText={() => {}}
  disabled
  minRows={6}
/>
